import { createRouter, createWebHistory } from "vue-router";
import ProductList from "@/components/ProductList.vue";
import ProductForm from "@/components/ProductForm.vue";
import AboutUs from "@/components/AboutUs.vue";
import AccountLogin from "@/components/AccountLogin.vue";
import { useAuthStore } from "@/store/auth";

const routes = [
  { path: "/home", component: ProductList },
  { path: "/form", component: ProductForm, meta: { requiresAdmin: true } }, // Chỉ Admin mới vào được
  { path: "/about", component: AboutUs },
  { path: "/login", component: AccountLogin },
];

const router = createRouter({
  history: createWebHistory(),
  routes,
});

router.beforeEach((to, from, next) => {
  const authStore = useAuthStore();

  // Kiểm tra nếu route cần quyền Admin mà user không phải Admin
  if (to.meta.requiresAdmin && authStore.role !== "admin") {
    alert("Bạn không có quyền truy cập vào trang này!");
    next("/home"); // Chuyển hướng về trang chủ
  } else {
    next();
  }
});

export default router;
